mapper.select:
SELECT COUNT(*)
FROM attach_file
WHERE target_type = #{targetType}
  AND target_id   = #{targetId}

mapper.update:
UPDATE attach_file
   SET is_rep = 'N'
 WHERE target_type = #{targetType}
   AND target_id   = #{targetId}
   AND is_rep      = 'Y'

UPDATE attach_file
   SET is_rep = 'Y'
 WHERE file_id   = #{fileId}
   AND member_id = #{memberId}

mapper.delete:
DELETE FROM attach_file
WHERE file_id   = #{fileId}
  AND member_id = #{memberId}

DELETE FROM attach_file
WHERE target_type = #{targetType}
  AND target_id   = #{targetId}
